<?php
namespace Database\Seeders;use App\Models\Region;use App\Models\World;use App\Models\WorldMap;use App\Models\WorldMapArea;use App\Models\Zone;use Carbon\CarbonImmutable;use Illuminate\Database\Seeder;use Illuminate\Support\Facades\DB;use Illuminate\Support\Facades\Storage;use RuntimeException;
class WorldMapTestingSeeder extends Seeder{public function run(){if(!app()->environment('testing')||substr((string)DB::connection()->getDatabaseName(),-8)!=='_testing')throw new RuntimeException('WorldMapTestingSeeder requires an isolated _testing database.');$fixture=base_path('tests/Fixtures/world-maps/eldoria-test-map.png.base64');if(!is_file($fixture))throw new RuntimeException('WorldMap testing fixture is missing.');$binary=base64_decode(trim((string)file_get_contents($fixture)),true);if($binary===false)throw new RuntimeException('WorldMap testing fixture is invalid.');$disk=(string)config('world_maps.disk','public');$path='world-maps/testing/eldoria-test-map.png';Storage::disk($disk)->put($path,$binary);$world=World::where('code','eldoria')->firstOrFail();$region=Region::where('world_id',$world->id)->where('code','kingdom_of_valtheria')->firstOrFail();$zone=Zone::where('region_id',$region->id)->where('code','grey_oak_forest')->firstOrFail();$common=['image_disk'=>$disk,'image_path'=>$path,'original_width'=>1,'original_height'=>1,'mime_type'=>'image/png','file_size'=>strlen($binary),'status'=>'active','is_default'=>true,'sort_order'=>1];$worldMap=WorldMap::updateOrCreate(['code'=>'eldoria_testing_map'],array_merge($common,['world_id'=>$world->id,'region_id'=>null,'name'=>'Mapa de Eldoria (testing)','description'=>'Fixture visual exclusivo de testing.']));$regionMap=WorldMap::updateOrCreate(['code'=>'valtheria_testing_map'],array_merge($common,['world_id'=>null,'region_id'=>$region->id,'name'=>'Mapa de Valtheria (testing)','description'=>'Fixture regional exclusivo de testing.']));$polygon=['coordinate_system'=>'normalized','points'=>[['x'=>0.1,'y'=>0.1],['x'=>0.4,'y'=>0.1],['x'=>0.2,'y'=>0.4]]];$this->area($worldMap,'grey_oak_zone',['name'=>'Bosque de Roblegris','action_type'=>'zone','zone_id'=>$zone->id,'description'=>null,'status'=>'active','polygon_points'=>$polygon]);$this->area($worldMap,'to_valtheria',['name'=>'Abrir Valtheria','action_type'=>'map','target_world_map_id'=>$regionMap->id,'description'=>null,'status'=>'active','polygon_points'=>$polygon,'z_index'=>2]);$this->area($regionMap,'back_to_eldoria',['name'=>'Volver a Eldoria','action_type'=>'map','target_world_map_id'=>$worldMap->id,'description'=>null,'status'=>'active','polygon_points'=>$polygon]);$this->area($worldMap,'eldoria_info',['name'=>'Información','action_type'=>'info','description'=>'Eldoria es el mundo inicial de pruebas.','status'=>'active','polygon_points'=>$polygon]);$this->area($worldMap,'inactive_area',['name'=>'Oculta','action_type'=>'info','description'=>'Área inactiva.','status'=>'inactive','polygon_points'=>$polygon]);$this->area($worldMap,'future_area',['name'=>'Próximamente','action_type'=>'info','description'=>'Contenido futuro.','status'=>'active','available_from'=>CarbonImmutable::now()->addDay(),'polygon_points'=>$polygon]);$this->area($regionMap,'world_default',['name'=>'Mapa mundial','action_type'=>'world','target_world_id'=>$world->id,'description'=>null,'status'=>'active','polygon_points'=>$polygon]);$this->area($worldMap,'region_default',['name'=>'Mapa regional','action_type'=>'region','target_region_id'=>$region->id,'description'=>null,'status'=>'active','polygon_points'=>$polygon]);}private function area($map,$code,$data){WorldMapArea::updateOrCreate(['world_map_id'=>$map->id,'code'=>$code],array_merge(['name'=>$code,'description'=>null,'polygon_points'=>null,'action_type'=>'info','display_mode'=>'panel','z_index'=>0,'fill_color'=>'#0d6efd','fill_opacity'=>0.25,'stroke_color'=>'#ffffff','stroke_width'=>2,'hover_fill_color'=>'#ffc107','hover_fill_opacity'=>0.45,'status'=>'draft','sort_order'=>0,'version'=>1],$data));}}
